1404:     private void reportCompletedCheckpoint(CompletedCheckpoint completedCheckpoint) {
1405:         failureManager.handleCheckpointSuccess(completedCheckpoint.getCheckpointID());
1406:         CompletedCheckpointStats completedCheckpointStats = completedCheckpoint.getStatistic();
1407:         if (completedCheckpointStats != null) {
1408:             LOG.trace(
1409:                     "Checkpoint {} size: {}Kb, duration: {}ms",
1410:                     completedCheckpoint.getCheckpointID(),
1411:                     completedCheckpointStats.getStateSize() == 0
1412:                             ? 0
1413:                             : completedCheckpointStats.getStateSize() / 1024,
1414:                     completedCheckpointStats.getEndToEndDuration());
1415:             // Finalize the statsCallback and give the completed checkpoint a
1416:             // callback for discards.
1417:             statsTracker.reportCompletedCheckpoint(completedCheckpointStats);
1418:         }
1419:     }
1420: 
1421:     private void cleanupAfterCompletedCheckpoint(
1422:             PendingCheckpoint pendingCheckpoint,
1423:             long checkpointId,
1424:             CompletedCheckpoint completedCheckpoint,
1425:             CompletedCheckpoint lastSubsumed,
1426:             CheckpointProperties props) {
1427: 
1428:         // record the time when this was completed, to calculate
1429:         // the 'min delay between checkpoints'
1430:         lastCheckpointCompletionRelativeTime = clock.relativeTimeMillis();
1431: 
1432:         logCheckpointInfo(completedCheckpoint);
1433: 
1434:         if (!props.isSavepoint() || props.isSynchronous()) {
1435:             // drop those pending checkpoints that are at prior to the completed one
1436:             dropSubsumedCheckpoints(checkpointId);
1437: 
1438:             // send the "notify complete" call to all vertices, coordinators, etc.
1439:             sendAcknowledgeMessages(
1440:                     pendingCheckpoint.getCheckpointPlan().getTasksToCommitTo(),
1441:                     checkpointId,
1442:                     completedCheckpoint.getTimestamp(),
1443:                     extractIdIfDiscardedOnSubsumed(lastSubsumed));
1444:         }
1445:     }
