1447:     private void logCheckpointInfo(CompletedCheckpoint completedCheckpoint) {
1448:         LOG.info(
1449:                 "Completed checkpoint {} for job {} ({} bytes, checkpointDuration={} ms, finalizationTime={} ms).",
1450:                 completedCheckpoint.getCheckpointID(),
1451:                 job,
1452:                 completedCheckpoint.getStateSize(),
1453:                 completedCheckpoint.getCompletionTimestamp() - completedCheckpoint.getTimestamp(),
1454:                 System.currentTimeMillis() - completedCheckpoint.getCompletionTimestamp());
1455: 
1456:         if (LOG.isDebugEnabled()) {
1457:             StringBuilder builder = new StringBuilder();
1458:             builder.append("Checkpoint state: ");
1459:             for (OperatorState state : completedCheckpoint.getOperatorStates().values()) {
1460:                 builder.append(state);
1461:                 builder.append(", ");
1462:             }
1463:             // Remove last two chars ", "
1464:             builder.setLength(builder.length() - 2);
1465: 
1466:             LOG.debug(builder.toString());
1467:         }
1468:     }
