1470:     private CompletedCheckpoint finalizeCheckpoint(PendingCheckpoint pendingCheckpoint)
1471:             throws CheckpointException {
1472:         try {
1473:             final CompletedCheckpoint completedCheckpoint =
1474:                     pendingCheckpoint.finalizeCheckpoint(
1475:                             checkpointsCleaner, this::scheduleTriggerRequest, executor);
1476: 
1477:             return completedCheckpoint;
1478:         } catch (Exception e1) {
1479:             // abort the current pending checkpoint if we fails to finalize the pending
1480:             // checkpoint.
1481:             final CheckpointFailureReason failureReason =
1482:                     e1 instanceof PartialFinishingNotSupportedByStateException
1483:                             ? CheckpointFailureReason.CHECKPOINT_DECLINED_TASK_CLOSING
1484:                             : CheckpointFailureReason.FINALIZE_CHECKPOINT_FAILURE;
1485: 
1486:             if (!pendingCheckpoint.isDisposed()) {
1487:                 abortPendingCheckpoint(
1488:                         pendingCheckpoint, new CheckpointException(failureReason, e1));
1489:             }
1490: 
1491:             throw new CheckpointException(
1492:                     "Could not finalize the pending checkpoint "
1493:                             + pendingCheckpoint.getCheckpointID()
1494:                             + '.',
1495:                     failureReason,
1496:                     e1);
1497:         }
1498:     }
