1500:     private long extractIdIfDiscardedOnSubsumed(CompletedCheckpoint lastSubsumed) {
1501:         final long lastSubsumedCheckpointId;
1502:         if (lastSubsumed != null && lastSubsumed.getProperties().discardOnSubsumed()) {
1503:             lastSubsumedCheckpointId = lastSubsumed.getCheckpointID();
1504:         } else {
1505:             lastSubsumedCheckpointId = CheckpointStoreUtil.INVALID_CHECKPOINT_ID;
1506:         }
1507:         return lastSubsumedCheckpointId;
1508:     }
1509: 
1510:     private CompletedCheckpoint addCompletedCheckpointToStoreAndSubsumeOldest(
1511:             long checkpointId,
1512:             CompletedCheckpoint completedCheckpoint,
1513:             PendingCheckpoint pendingCheckpoint)
1514:             throws CheckpointException {
1515:         List<ExecutionVertex> tasksToAbort =
1516:                 pendingCheckpoint.getCheckpointPlan().getTasksToCommitTo();
1517:         try {
1518:             final CompletedCheckpoint subsumedCheckpoint =
1519:                     completedCheckpointStore.addCheckpointAndSubsumeOldestOne(
1520:                             completedCheckpoint, checkpointsCleaner, this::scheduleTriggerRequest);
1521:             // reset the force full snapshot flag, we should've completed at least one full
1522:             // snapshot by now
1523:             this.forceFullSnapshot = false;
1524:             return subsumedCheckpoint;
1525:         } catch (Exception exception) {
1526:             pendingCheckpoint.getCompletionFuture().completeExceptionally(exception);
1527:             if (exception instanceof PossibleInconsistentStateException) {
1528:                 LOG.warn(
1529:                         "An error occurred while writing checkpoint {} to the underlying metadata"
1530:                                 + " store. Flink was not able to determine whether the metadata was"
1531:                                 + " successfully persisted. The corresponding state located at '{}'"
1532:                                 + " won't be discarded and needs to be cleaned up manually.",
1533:                         completedCheckpoint.getCheckpointID(),
1534:                         completedCheckpoint.getExternalPointer());
1535:             } else {
1536:                 // we failed to store the completed checkpoint. Let's clean up
1537:                 checkpointsCleaner.cleanCheckpointOnFailedStoring(completedCheckpoint, executor);
1538:             }
1539: 
1540:             final CheckpointException checkpointException =
1541:                     new CheckpointException(
1542:                             "Could not complete the pending checkpoint " + checkpointId + '.',
1543:                             CheckpointFailureReason.FINALIZE_CHECKPOINT_FAILURE,
1544:                             exception);
1545:             reportFailedCheckpoint(pendingCheckpoint, checkpointException);
1546:             sendAbortedMessages(tasksToAbort, checkpointId, completedCheckpoint.getTimestamp());
1547:             throw checkpointException;
1548:         }
1549:     }
