40: /**
41:  * The {@link CheckpointBarrierHandler} reacts to checkpoint barrier arriving from the input
42:  * channels. Different implementations may either simply track barriers, or block certain inputs on
43:  * barriers.
44:  */
45: public abstract class CheckpointBarrierHandler implements Closeable {
46:     private static final long OUTSIDE_OF_ALIGNMENT = Long.MIN_VALUE;
47: 
48:     /** The listener to be notified on complete checkpoints. */
49:     private final CheckpointableTask toNotifyOnCheckpoint;
50: 
51:     private final Clock clock;
52: 
53:     /** The time (in nanoseconds) that the latest alignment took. */
54:     private CompletableFuture<Long> latestAlignmentDurationNanos = new CompletableFuture<>();
55: 
56:     /**
57:      * The time (in nanoseconds) between creation of the checkpoint's first checkpoint barrier and
58:      * receiving it by this task.
59:      */
60:     private long latestCheckpointStartDelayNanos;
61: 
62:     /** The timestamp as in {@link System#nanoTime()} at which the last alignment started. */
63:     private long startOfAlignmentTimestamp = OUTSIDE_OF_ALIGNMENT;
64: 
65:     /** ID of checkpoint for which alignment was started last. */
66:     private long startAlignmentCheckpointId = -1;
67: 
68:     /**
69:      * Cumulative counter of bytes processed during alignment. Once we complete alignment, we will
70:      * put this value into the {@link #latestBytesProcessedDuringAlignment}.
71:      */
72:     private long bytesProcessedDuringAlignment;
73: 
74:     private CompletableFuture<Long> latestBytesProcessedDuringAlignment = new CompletableFuture<>();
75: 
76:     private final boolean enableCheckpointAfterTasksFinished;
77: 
78:     public CheckpointBarrierHandler(
79:             CheckpointableTask toNotifyOnCheckpoint,
80:             Clock clock,
81:             boolean enableCheckpointAfterTasksFinished) {
82:         this.toNotifyOnCheckpoint = checkNotNull(toNotifyOnCheckpoint);
83:         this.clock = checkNotNull(clock);
84:         this.enableCheckpointAfterTasksFinished = enableCheckpointAfterTasksFinished;
85:     }
86: 
87:     boolean isCheckpointAfterTasksFinishedEnabled() {
88:         return enableCheckpointAfterTasksFinished;
89:     }
90: 
91:     @Override
92:     public void close() throws IOException {}
93: 
94:     public abstract void processBarrier(
95:             CheckpointBarrier receivedBarrier, InputChannelInfo channelInfo, boolean isRpcTriggered)
96:             throws IOException;
97: 
98:     public abstract void processBarrierAnnouncement(
99:             CheckpointBarrier announcedBarrier, int sequenceNumber, InputChannelInfo channelInfo)
100:             throws IOException;
101: 
102:     public abstract void processCancellationBarrier(
103:             CancelCheckpointMarker cancelBarrier, InputChannelInfo channelInfo) throws IOException;
104: 
105:     public abstract void processEndOfPartition(InputChannelInfo channelInfo) throws IOException;
106: 
107:     public abstract long getLatestCheckpointId();
108: 
109:     public long getAlignmentDurationNanos() {
110:         if (isDuringAlignment()) {
111:             return clock.relativeTimeNanos() - startOfAlignmentTimestamp;
112:         } else {
113:             return FutureUtils.getOrDefault(latestAlignmentDurationNanos, 0L);
114:         }
115:     }
116: 
117:     public long getCheckpointStartDelayNanos() {
118:         return latestCheckpointStartDelayNanos;
119:     }
120: 
121:     public CompletableFuture<Void> getAllBarriersReceivedFuture(long checkpointId) {
122:         return CompletableFuture.completedFuture(null);
123:     }
124: 
125:     protected void notifyCheckpoint(CheckpointBarrier checkpointBarrier) throws IOException {
126:         CheckpointMetaData checkpointMetaData =
127:                 new CheckpointMetaData(
128:                         checkpointBarrier.getId(),
129:                         checkpointBarrier.getTimestamp(),
130:                         System.currentTimeMillis());
131: 
132:         CheckpointMetricsBuilder checkpointMetrics;
133:         if (checkpointBarrier.getId() == startAlignmentCheckpointId) {
134:             checkpointMetrics =
135:                     new CheckpointMetricsBuilder()
136:                             .setAlignmentDurationNanos(latestAlignmentDurationNanos)
137:                             .setBytesProcessedDuringAlignment(latestBytesProcessedDuringAlignment)
138:                             .setCheckpointStartDelayNanos(latestCheckpointStartDelayNanos);
139:         } else {
140:             checkpointMetrics =
141:                     new CheckpointMetricsBuilder()
142:                             .setAlignmentDurationNanos(0L)
143:                             .setBytesProcessedDuringAlignment(0L)
144:                             .setCheckpointStartDelayNanos(0);
145:         }
146: 
147:         toNotifyOnCheckpoint.triggerCheckpointOnBarrier(
148:                 checkpointMetaData, checkpointBarrier.getCheckpointOptions(), checkpointMetrics);
149:     }
