1353:     /**
1354:      * Calls the invokable to trigger a checkpoint.
1355:      *
1356:      * @param checkpointID The ID identifying the checkpoint.
1357:      * @param checkpointTimestamp The timestamp associated with the checkpoint.
1358:      * @param checkpointOptions Options for performing this checkpoint.
1359:      */
1360:     public void triggerCheckpointBarrier(
1361:             final long checkpointID,
1362:             final long checkpointTimestamp,
1363:             final CheckpointOptions checkpointOptions) {
1364: 
1365:         final TaskInvokable invokable = this.invokable;
1366:         final CheckpointMetaData checkpointMetaData =
1367:                 new CheckpointMetaData(
1368:                         checkpointID, checkpointTimestamp, System.currentTimeMillis());
1369: 
1370:         if (executionState == ExecutionState.RUNNING) {
1371:             checkState(invokable instanceof CheckpointableTask, "invokable is not checkpointable");
1372:             try {
1373:                 ((CheckpointableTask) invokable)
1374:                         .triggerCheckpointAsync(checkpointMetaData, checkpointOptions)
1375:                         .handle(
1376:                                 (triggerResult, exception) -> {
1377:                                     if (exception != null || !triggerResult) {
1378:                                         declineCheckpoint(
1379:                                                 checkpointID,
1380:                                                 CheckpointFailureReason.TASK_FAILURE,
1381:                                                 exception);
1382:                                         return false;
1383:                                     }
1384:                                     return true;
1385:                                 });
1386:             } catch (RejectedExecutionException ex) {
1387:                 // This may happen if the mailbox is closed. It means that the task is shutting
1388:                 // down, so we just ignore it.
1389:                 LOG.debug(
1390:                         "Triggering checkpoint {} for {} ({}) was rejected by the mailbox",
1391:                         checkpointID,
1392:                         taskNameWithSubtask,
1393:                         executionId);
1394:                 declineCheckpoint(
1395:                         checkpointID, CheckpointFailureReason.CHECKPOINT_DECLINED_TASK_CLOSING);
1396:             } catch (Throwable t) {
1397:                 if (getExecutionState() == ExecutionState.RUNNING) {
1398:                     failExternally(
1399:                             new Exception(
1400:                                     "Error while triggering checkpoint "
1401:                                             + checkpointID
1402:                                             + " for "
1403:                                             + taskNameWithSubtask,
1404:                                     t));
1405:                 } else {
1406:                     LOG.debug(
1407:                             "Encountered error while triggering checkpoint {} for "
1408:                                     + "{} ({}) while being not in state running.",
1409:                             checkpointID,
1410:                             taskNameWithSubtask,
1411:                             executionId,
1412:                             t);
1413:                 }
1414:             }
1415:         } else {
1416:             LOG.debug(
1417:                     "Declining checkpoint request for non-running task {} ({}).",
1418:                     taskNameWithSubtask,
1419:                     executionId);
1420: 
1421:             // send back a message that we did not do the checkpoint
1422:             declineCheckpoint(
1423:                     checkpointID, CheckpointFailureReason.CHECKPOINT_DECLINED_TASK_NOT_READY);
1424:         }
1425:     }
